vector<bool> vis(N, false);
vector<pair<int,int>> adj[N];

vector<pair<int,int>> MST; // Stores the edge list of the Minimum Spanning Tree

bool cmp(vector<int> &a, vector<int> &b) {
    if(a[0] > b[0]) return true;
    return false;
}

void prims(int source, int n) { // Source is the starting vertex

    // Stores weight, newly added vertex and parent vertex
    priority_queue<vector<int>, vector<vector<int>>, decltype(&cmp)> pq(cmp);

    pq.push({0, source}); // push the staring vertex to the pq

    while(pq.size() != 0) {
        vector<int> node = pq.top();
        pq.pop();

        int v = node[1];

        // If vertex is already processed, continue
        if(vis[v]) {
            continue;
        }

        vis[v] = 1; // Mark vertes as processed

        cout << "Adding vertex " << v << " to the MST\n";

        if(node.size() == 3) {
            MST.push_back({node[2], v}); // Push the edge into the MST;
        }

        for(auto edge: adj[v]) {
            pq.push({edge.second, edge.first, v});   
        }
    }      

    cout << "\nEdgelist of MST is:\n";

    for(auto edge: MST) {
        cout << edge.first << " " << edge.second << "\n";
    }
}


