#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#define N 100  // Increased size to handle larger inputs

bool vis[N];
int adj[N][N];  // Adjacency matrix
int edges[N][3];  // Edge list for the priority queue
int edge_count;

typedef struct {
    int weight;
    int vertex;
    int parent;
} Edge;

Edge MST[N];  // Stores the edges of the Minimum Spanning Tree
int mst_count;

// Rest of the helper functions remain the same
int cmp(const void *a, const void *b) {
    Edge *edgeA = (Edge *)a;
    Edge *edgeB = (Edge *)b;
    return edgeA->weight - edgeB->weight;
}

void push_edge(int weight, int vertex, int parent) {
    edges[edge_count][0] = weight;
    edges[edge_count][1] = vertex;
    edges[edge_count][2] = parent;
    edge_count++;
}

Edge pop_edge() {
    qsort(edges, edge_count, sizeof(edges[0]), cmp);
    Edge edge = {edges[0][0], edges[0][1], edges[0][2]};
    for (int i = 1; i < edge_count; i++) {
        edges[i-1][0] = edges[i][0];
        edges[i-1][1] = edges[i][1];
        edges[i-1][2] = edges[i][2];
    }
    edge_count--;
    return edge;
}

void prims(int source, int n) {
    push_edge(0, source, -1);  // Push the starting vertex to the pq
    while (edge_count > 0) {
        Edge edge = pop_edge();
        int v = edge.vertex;
        if (vis[v]) continue;

        vis[v] = true;
        if (edge.parent != -1) {
            MST[mst_count++] = edge;
        }

        for (int u = 1; u <= n; u++) {
            if (adj[v][u] && !vis[u]) {
                push_edge(adj[v][u], u, v);
            }
        }
    }

    // Print total weight of MST
    int total_weight = 0;
    for (int i = 0; i < mst_count; i++) {
        total_weight += MST[i].weight;
    }
    printf("%d\n", total_weight);

    // Print edges of MST
    for (int i = 0; i < mst_count; i++) {
        printf("%d %d\n", MST[i].parent, MST[i].vertex);
    }
}

int main() {
    int n, m;  // n: vertices, m: edges
    scanf("%d %d", &n, &m);

    // Initialize the adjacency matrix
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            adj[i][j] = 0;
        }
        vis[i] = false;
    }

    // Read edges
    for (int i = 0; i < m; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        adj[u][v] = w;
        adj[v][u] = w;  // Undirected graph
    }

    edge_count = 0;
    mst_count = 0;
    prims(1, n);  // Start from vertex 1

    return 0;
}

