class MinHeap {
    constructor() {
        this.heap = [];
    }

    push(item) {
        this.heap.push(item);
        this.heapifyUp();
    }

    pop() {
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown();

        return min;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    heapifyUp() {
        let index = this.heap.length - 1;

        while (index > 0) {
            let parent = Math.floor((index - 1) / 2);

            if (this.heap[parent][0] <= this.heap[index][0]) break;

            [this.heap[parent], this.heap[index]] =
                [this.heap[index], this.heap[parent]];

            index = parent;
        }
    }

    heapifyDown() {
        let index = 0;

        while (true) {
            let left = 2 * index + 1;
            let right = 2 * index + 2;
            let smallest = index;

            if (
                left < this.heap.length &&
                this.heap[left][0] < this.heap[smallest][0]
            ) {
                smallest = left;
            }

            if (
                right < this.heap.length &&
                this.heap[right][0] < this.heap[smallest][0]
            ) {
                smallest = right;
            }

            if (smallest === index) break;

            [this.heap[index], this.heap[smallest]] =
                [this.heap[smallest], this.heap[index]];

            index = smallest;
        }
    }
}

function primMST(n, graph) {
    const visited = new Array(n + 1).fill(false);
    const pq = new MinHeap();

    let mstWeight = 0;
    const mstEdges = [];

    visited[1] = true;

    for (const [to, weight] of graph[1]) {
        pq.push([weight, 1, to]);
    }

    while (!pq.isEmpty()) {
        const [weight, from, to] = pq.pop();

        if (visited[to]) continue;

        visited[to] = true;
        mstWeight += weight;
        mstEdges.push([from, to, weight]);

        for (const [next, nextWeight] of graph[to]) {
            if (!visited[next]) {
                pq.push([nextWeight, to, next]);
            }
        }
    }

    console.log("MST Weight =", mstWeight);

    console.log("Edges in MST:");
    for (const [u, v, w] of mstEdges) {
        console.log(`${u} - ${v} (${w})`);
    }
}

